mapper.select:
SELECT 
FROM videos
JOIN users u ON u.id = videos.user_id
JOIN gyms g ON g.id = videos.gym_id
JOIN gym_grades gg ON gg.id = videos.gym_grade_id AND gg.gym_id = videos.gym_id
WHERE videos.deleted_at IS NULL


    AND videos.user_id = #{userId}


    AND (
        videos.recorded_date < #{cursorRecordedDate}
        OR (videos.recorded_date = #{cursorRecordedDate} AND videos.id < #{cursorId})
    )


    AND videos.recorded_date = #{recordedDate}


ORDER BY videos.recorded_date DESC, videos.id DESC
LIMIT #{limit}

SELECT FROM videos JOIN users u ON u.id = videos.user_id JOIN gyms g ON g.id = videos.gym_id JOIN gym_grades gg ON gg.id = videos.gym_grade_id AND gg.gym_id = videos.gym_id WHERE videos.deleted_at IS NULL
AND videos.gym_id = #{gymId}
ORDER BY videos.created_at DESC, videos.id DESC LIMIT #{size} OFFSET #{offset}
